import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Modifier;

class CSVFormatTest {

    @Test
    void testIsCommentMarkerSet_WhenCommentMarkerIsNull() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Use reflection to get the "commentMarker" field in CSVFormat
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);

        // Remove final modifier from the commentMarker field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(commentMarkerField, commentMarkerField.getModifiers() & ~Modifier.FINAL);

        // Create a new instance of CSVFormat with commentMarker set to null via withCommentMarker method
        CSVFormat modifiedCsvFormat = csvFormat.withCommentMarker((Character) null);

        // Manually set the commentMarker field of the new instance to null (redundant but ensures)
        commentMarkerField.set(modifiedCsvFormat, null);

        assertFalse(modifiedCsvFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_WhenCommentMarkerIsSet() throws Exception {
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // Use reflection to get the "commentMarker" field in CSVFormat
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);

        // Remove final modifier from the commentMarker field
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(commentMarkerField, commentMarkerField.getModifiers() & ~Modifier.FINAL);

        // Create a new instance of CSVFormat with commentMarker set to '#'
        CSVFormat modifiedCsvFormat = csvFormat.withCommentMarker('#');

        // Manually set the commentMarker field of the new instance to '#'
        commentMarkerField.set(modifiedCsvFormat, Character.valueOf('#'));

        assertTrue(modifiedCsvFormat.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_WithWithCommentMarkerMethod() {
        CSVFormat csvFormat = CSVFormat.DEFAULT.withCommentMarker('#');
        assertTrue(csvFormat.isCommentMarkerSet());

        CSVFormat csvFormatNull = CSVFormat.DEFAULT.withCommentMarker((Character) null);
        assertFalse(csvFormatNull.isCommentMarkerSet());
    }
}
